| final ruler = [[Manabe Akinobu]]
| noteworthy members = [[Manabe Akifusa]], [[Manabe Akikatsu]]
| branches = Honjo Manabe clan ([[Samurai]])<br/>Akasaka Manabe clan ([[Samurai]])
